final:
module gray_code_counter_2bit(
    input clk,
    input rst,

    output reg [1:0] gray_q
);

reg [1:0] invalid_gray;  // Internal binary counter

// Gray Code Counter logic
always @(posedge clk) begin
    if (rst)
        invalid_gray <= 2'b00;
    else
        invalid_gray <= invalid_gray + 1;
end

// Convert binary counter to Gray code
always @(invalid_gray) begin
    gray_q = invalid_gray ^ (invalid_gray >> 1);
end

endmodule
